import React, { useState, useEffect } from "react";
import axios from "axios";
import Grid from "@material-ui/core/Grid";


import Today from "./PolandComponents/Today";
import Total from "./PolandComponents/Total";
import PolandChart from "./PolandComponents/PolandChart";

let intervalId = null;



const Poland = () => {
  const [timeline, setTimeline] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    todayNew: 0,
    todayDeaths: 0,
    todayRecovered: 0,
    totalConfirmed: 0,
    totalDeaths: 0,
    totalRecovered: 0,
    updateDate: 0
  });
  useEffect(() => {
    axios
      .get("https://corona-api.com/countries/PL")
      .then(res => {
        //console.log(res.data.data.updated_at);
        setStats({
          todayNew: res.data.data.today.confirmed || 0,
          todayDeaths: res.data.data.today.deaths || 0,
          todayRecovered: res.data.data.today.recovered || 0,
          totalConfirmed: res.data.data.latest_data.confirmed || 0,
          totalDeaths: res.data.data.latest_data.deaths || 0,
          totalRecovered: res.data.data.latest_data.recovered || 0,
          updateDate: res.data.data.updated_at || 0,
          active:
            res.data.data.latest_data.confirmed -
              res.data.data.latest_data.deaths -
              res.data.data.latest_data.recovered || 0
        });
        setLoading(false);
        setTimeline(res.data.data.timeline);
      })
      .catch(err => {
        console.error(err);
      });

    intervalId = setInterval(() => {
      axios.get("https://corona-api.com/countries/PL").then(res => {
        setTimeline(res.data.data.timeline);
        setStats({
          todayNew: res.data.data.today.confirmed || 0,
          todayDeaths: res.data.data.today.deaths || 0,
          todayRecovered: res.data.data.today.recovered || 0,
          totalConfirmed: res.data.data.latest_data.confirmed || 0,
          totalDeaths: res.data.data.latest_data.deaths || 0,
          totalRecovered: res.data.data.latest_data.recovered || 0,
          updateDate: res.data.data.updated_at || 0,
          active:
            res.data.data.latest_data.confirmed -
              res.data.data.latest_data.deaths -
              res.data.data.latest_data.recovered || 0
        });
      });
    }, 300000);

    return () => {
      clearInterval(intervalId);
    };
  }, []);
  return (
    <>
      {loading ? (
        <h2 style={{ textAlign: "center" }}>Loading...</h2>
      ) : (
        <Grid container>
          <Grid item xs={12} md={3}>
            <Total stats={stats} />
          </Grid>
          <Grid item xs={12} md={9}>
            <Today stats={stats} />
            <PolandChart timeline={timeline} active={stats.active} />
          </Grid>
        </Grid>
      )}
    </>
  );
};

export default Poland;
